namespace sv_00aab1c6013b44f49ea24cd572e4a974.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public sealed class ShipmentDetails
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public required DateTimeOffset EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required DateTimeOffset Timestamp { get; init; }
    public required string Description { get; init; }
}

using sv_00aab1c6013b44f49ea24cd572e4a974.Client.Services;

namespace sv_00aab1c6013b44f49ea24cd572e4a974.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-1001"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-1001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 2, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 8, 0, 0, TimeSpan.Zero), Description = "Package picked up" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 14, 30, 0, TimeSpan.Zero), Description = "Arrived at sorting facility — Memphis, TN" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 23, 9, 15, 0, TimeSpan.Zero), Description = "Departed sorting facility" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 25, 11, 0, 0, TimeSpan.Zero), Description = "In transit — Chicago, IL" },
            ]
        },
        ["TRK-2002"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-2002",
            Status = "Delivered",
            Location = "Austin, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 24, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero), Description = "Package picked up" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 19, 16, 0, 0, TimeSpan.Zero), Description = "Arrived at sorting facility — Dallas, TX" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 7, 45, 0, TimeSpan.Zero), Description = "Out for delivery" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 13, 20, 0, TimeSpan.Zero), Description = "Delivered — signed by J. Smith" },
            ]
        },
        ["TRK-3003"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-3003",
            Status = "Processing",
            Location = "Seattle, WA",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 5, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 25, 22, 10, 0, TimeSpan.Zero), Description = "Order placed" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 26, 6, 0, 0, TimeSpan.Zero), Description = "Processing at warehouse — Seattle, WA" },
            ]
        }
    };

    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);
        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using System.Net;
using System.Net.Http.Json;

namespace sv_00aab1c6013b44f49ea24cd572e4a974.Client.Services;

/// <summary>
/// HTTP-based implementation used when running on WebAssembly.
/// Calls the server API to retrieve shipment data.
/// </summary>
public sealed class ShipmentClientService(HttpClient http) : IShipmentService
{
    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var encoded = Uri.EscapeDataString(trackingNumber);
        var response = await http.GetAsync($"api/shipments/{encoded}", ct);

        if (response.StatusCode == HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct);
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_00aab1c6013b44f49ea24cd572e4a974.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<Shipment> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <p><em>Loading shipment @TrackingNumber…</em></p>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
}
else
{
    <h3>Shipment @_shipment.TrackingNumber</h3>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Location</dt>
        <dd>@_shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h4>Status Updates</h4>
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Time</th>
                <th>Description</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var update in _shipment.StatusUpdates)
            {
                <tr>
                    <td>@update.Timestamp.ToString("g")</td>
                    <td>@update.Description</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter] public string TrackingNumber { get; set; } = "";

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request (handles route-parameter changes and retries).
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _shipment = null;
        _errorMessage = null;
        _loading = true;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // The request was intentionally cancelled — nothing to show.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync() => await LoadShipmentAsync();

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

